2497 /// Check if instruction depends on ZExt and this ZExt can be moved after the
2498 /// instruction. Move ZExt if it is profitable. For example:
2499 ///     logic(zext(x),y) -> zext(logic(x,trunc(y)))
2500 ///     lshr((zext(x),y) -> zext(lshr(x,trunc(y)))
2501 /// Cost model calculations takes into account if zext(x) has other users and
2502 /// whether it can be propagated through them too.
2503 bool VectorCombine::shrinkType(llvm::Instruction &I) {
2504   Value *ZExted, *OtherOperand;
2505   if (!match(&I, m_c_BitwiseLogic(m_ZExt(m_Value(ZExted)),
2506                                   m_Value(OtherOperand))) &&
2507       !match(&I, m_LShr(m_ZExt(m_Value(ZExted)), m_Value(OtherOperand))))
2508     return false;
2509 
2510   Value *ZExtOperand = I.getOperand(I.getOperand(0) == OtherOperand ? 1 : 0);
2511 
2512   auto *BigTy = cast<FixedVectorType>(I.getType());
2513   auto *SmallTy = cast<FixedVectorType>(ZExted->getType());
2514   unsigned BW = SmallTy->getElementType()->getPrimitiveSizeInBits();
2515 
2516   // Check that the expression overall uses at most the same number of bits as
2517   // ZExted
2518   KnownBits KB = computeKnownBits(&I, *DL);
2519   if (KB.countMaxActiveBits() > BW)
2520     return false;
2521 
2522   // Calculate costs of leaving current IR as it is and moving ZExt operation
2523   // later, along with adding truncates if needed
2524   TTI::TargetCostKind CostKind = TTI::TCK_RecipThroughput;
2525   InstructionCost ZExtCost = TTI.getCastInstrCost(
2526       Instruction::ZExt, BigTy, SmallTy,
2527       TargetTransformInfo::CastContextHint::None, CostKind);
2528   InstructionCost CurrentCost = ZExtCost;
2529   InstructionCost ShrinkCost = 0;
2530 
2531   // Calculate total cost and check that we can propagate through all ZExt users
2532   for (User *U : ZExtOperand->users()) {
2533     auto *UI = cast<Instruction>(U);
2534     if (UI == &I) {
2535       CurrentCost +=
2536           TTI.getArithmeticInstrCost(UI->getOpcode(), BigTy, CostKind);
2537       ShrinkCost +=
2538           TTI.getArithmeticInstrCost(UI->getOpcode(), SmallTy, CostKind);
2539       ShrinkCost += ZExtCost;
2540       continue;
2541     }
2542 
2543     if (!Instruction::isBinaryOp(UI->getOpcode()))
2544       return false;
2545 
2546     // Check if we can propagate ZExt through its other users
2547     KB = computeKnownBits(UI, *DL);
2548     if (KB.countMaxActiveBits() > BW)
2549       return false;
2550 
2551     CurrentCost += TTI.getArithmeticInstrCost(UI->getOpcode(), BigTy, CostKind);
2552     ShrinkCost +=
2553         TTI.getArithmeticInstrCost(UI->getOpcode(), SmallTy, CostKind);
2554     ShrinkCost += ZExtCost;
2555   }
2556 
2557   // If the other instruction operand is not a constant, we'll need to
2558   // generate a truncate instruction. So we have to adjust cost
2559   if (!isa<Constant>(OtherOperand))
2560     ShrinkCost += TTI.getCastInstrCost(
2561         Instruction::Trunc, SmallTy, BigTy,
2562         TargetTransformInfo::CastContextHint::None, CostKind);
2563 
2564   // If the cost of shrinking types and leaving the IR is the same, we'll lean
2565   // towards modifying the IR because shrinking opens opportunities for other
2566   // shrinking optimisations.
2567   if (ShrinkCost > CurrentCost)
2568     return false;
2569 
2570   Value *Op0 = ZExted;
2571   if (auto *OI = dyn_cast<Instruction>(OtherOperand))
2572     Builder.SetInsertPoint(OI->getNextNode());
2573   Value *Op1 = Builder.CreateTrunc(OtherOperand, SmallTy);
2574   Builder.SetInsertPoint(&I);
2575   // Keep the order of operands the same
2576   if (I.getOperand(0) == OtherOperand)
2577     std::swap(Op0, Op1);
2578   Value *NewBinOp =
2579       Builder.CreateBinOp((Instruction::BinaryOps)I.getOpcode(), Op0, Op1);
2580   cast<Instruction>(NewBinOp)->copyIRFlags(&I);
2581   cast<Instruction>(NewBinOp)->copyMetadata(I);
2582   Value *NewZExtr = Builder.CreateZExt(NewBinOp, BigTy);
2583   replaceValue(I, *NewZExtr);
2584   return true;
2585 }
